#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define grep(a,b,c) for(register int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
#define int long long
const int N=35005,M=35005;const long long INF=1e15;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
struct Graph{int head[N],des[M],nxt[M],cnt;inline void ins(int x,int y){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;}}g;
int len,a[N],mi[N],mx[N],dp[N],sl[N],sr[N];
signed main()
{
	int n=read();rep(1,n,i)a[i]=read()-i;a[0]=-(a[n+1]=INF); rep(1,n+1,i)
	{
		int l=0,r=len,mid,res=0;while(l<=r)(mi[mid=(l+r)>>1]<=a[i])?(res=mid,l=mid+1):(r=mid-1);
		len+=(res==len);g.ins(mx[i]=res+1,i);mi[res+1]=a[i];
	}
	printf("%lld\n",n-len+1); g.ins(0,0);rep(1,n+1,i)dp[i]=INF;
	rep(1,n+1,i)grep(g,mx[i]-1,j)
	{
		int tmp=g.des[j];if(tmp>i||a[tmp]>a[i])continue;sl[tmp]=sr[i-1]=0;
		rep(tmp+1,i-1,k)sl[k]=sl[k-1]+abs(a[k]-a[tmp]);drep(i-2,tmp,k)sr[k]=sr[k+1]+abs(a[k+1]-a[i]);
		rep(tmp,i-1,k)dp[i]=min(dp[i],dp[tmp]+sl[k]+sr[k]);
	}
	printf("%lld\n",dp[n+1]);return 0;
}
